package com.grit.liferecorder.ui.tasks
import androidx.lifecycle.*; import com.grit.liferecorder.core.date.*; import com.grit.liferecorder.data.local.entity.TaskEntity; import com.grit.liferecorder.data.repository.TaskRepository; import kotlinx.coroutines.flow.*; import kotlinx.coroutines.launch
data class TasksUiState(val tasks:List<TaskEntity> = emptyList(), val filter:String="All")
class TasksViewModel(private val repository:TaskRepository):ViewModel(){ private val filter=MutableStateFlow("All"); val state=combine(repository.observeAll(),filter){tasks,f-> TasksUiState(when(f){"Open"->tasks.filter{it.status=="Open"};"Completed"->tasks.filter{it.status=="Completed"};"Overdue"->tasks.filter{it.status=="Open" && it.completeByDate!=null && it.completeByDate < DateUtils.today()};else->tasks},f)}.stateIn(viewModelScope,SharingStarted.WhileSubscribed(5000),TasksUiState()); fun setFilter(f:String){filter.value=f}; fun add(title:String){ if(title.isNotBlank()) viewModelScope.launch{ repository.save(TaskEntity(title=title,completeByDate=DateUtils.today(),createdAt=TimeUtils.now(),updatedAt=TimeUtils.now())) } }; fun complete(t:TaskEntity)=viewModelScope.launch{repository.complete(t)}; fun cancel(t:TaskEntity)=viewModelScope.launch{repository.cancel(t)} }
